(function(){'use strict';const BTN_ID='jf-random-movie-btn';let isFetching=false;const ensureStyles=()=>{if(document.getElementById('jf-random-style'))return;const style=document.createElement('style');style.id='jf-random-style';style.textContent='@keyframes jf-spin-dice{0%{transform:rotate(0deg)}100%{transform:rotate(360deg)}}.jf-spinning{animation:jf-spin-dice .6s linear infinite;color:#10b981!important}';document.head.appendChild(style)};const playRandomMovie=async()=>{if(isFetching||typeof ApiClient==='undefined')return;const userId=ApiClient.getCurrentUserId();if(!userId)return;isFetching=true;const btn=document.getElementById(BTN_ID);const icon=btn?.querySelector('.material-icons');if(icon)icon.classList.add('jf-spinning');try{const response=await ApiClient.getJSON(ApiClient.getUrl(`Users/${userId}/Items`,{IncludeItemTypes:'Movie',Recursive:true,SortBy:'Random',Limit:1}));if(response&&response.Items&&response.Items.length>0){const movieId=response.Items[0].Id;window.location.hash=`#!/details?id=${movieId}`}}catch(err){console.error("Random Movie Button: Error fetching movie",err)}finally{isFetching=false;if(icon)icon.classList.remove('jf-spinning')}};const injectButton=()=>{if(document.getElementById(BTN_ID))return;const headerRight=document.querySelector('.headerRight');if(!headerRight)return;ensureStyles();const btn=document.createElement('button');btn.id=BTN_ID;btn.className='paper-icon-button-light headerButton';btn.title='Pick a Random Movie';const icon=document.createElement('span');icon.className='material-icons';icon.textContent='casino';btn.appendChild(icon);btn.addEventListener('click',(e)=>{e.preventDefault();e.stopPropagation();playRandomMovie()});headerRight.prepend(btn)};const checkPageState=()=>{const hash=window.location.hash;const isHome=hash===''||hash==='#!'||hash.includes('home');if(isHome){injectButton()}else{const btn=document.getElementById(BTN_ID);if(btn)btn.remove()}};const observer=new MutationObserver(checkPageState);if(document.readyState==='complete'||document.readyState==='interactive'){checkPageState();observer.observe(document.body,{childList:true,subtree:true})}else{window.addEventListener('DOMContentLoaded',()=>{checkPageState();observer.observe(document.body,{childList:true,subtree:true})})}window.addEventListener('hashchange',checkPageState)})();
